"use client";

import { useEffect, useRef } from "react";
import Image from "next/image";
import Link from "next/link";
import { Asterisk } from "lucide-react";
import gsap from "gsap";

interface ProjectHeroProps {
  project: {
    image: string;
    title: string;
  };
  nextProject: { slug: string; title: string } | null;
  previousProject: { slug: string; title: string } | null;
}

export default function ProjectHero({ project, nextProject, previousProject }: ProjectHeroProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const imageRef = useRef<HTMLDivElement>(null);
  const titleRef = useRef<HTMLHeadingElement>(null);
  const starLeftRef = useRef<SVGSVGElement>(null);
  const starRightRef = useRef<SVGSVGElement>(null);
  const buttonsRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const ctx = gsap.context(() => {
      const tl = gsap.timeline({ defaults: { ease: "power3.out" } });

      tl.fromTo(
        imageRef.current,
        { clipPath: "inset(100% 0% 0% 0%)" },
        { clipPath: "inset(0% 0% 0% 0%)", duration: 1.2, delay: 0.2 }
      );

      tl.fromTo(
        titleRef.current,
        { scale: 0.3, opacity: 0 },
        { scale: 1, opacity: 1, duration: 1 },
        "-=0.8"
      );

      tl.fromTo(
        starLeftRef.current,
        { x: -100, rotation: 180, opacity: 0 },
        { x: 0, rotation: 45, opacity: 1, duration: 1, ease: "back.out(1.5)" },
        "-=0.6"
      );
      tl.fromTo(
        starRightRef.current,
        { x: 100, rotation: -180, opacity: 0 },
        { x: 0, rotation: 45, opacity: 1, duration: 1, ease: "back.out(1.5)" },
        "<"
      );

      tl.fromTo(
        buttonsRef.current?.children,
        { opacity: 0, y: 10 },
        { opacity: 1, y: 0, duration: 0.6, stagger: 0.1 },
        "-=0.4"
      );
    }, containerRef);

    return () => ctx.revert();
  }, []);

  return (
    <div ref={containerRef} className="min-h-screen">
      {/* Image et Navigation */}
      <section className="relative w-full px-2 pt-2">
        <div ref={imageRef} className="relative w-full h-[calc(60vh-16px)] md:h-[calc(75vh-16px)] overflow-hidden">
          <Image
            src={project.image}
            alt={`${project.title} - Project showcase`}
            fill
            className="object-cover"
            priority
          />

          <nav
            ref={buttonsRef}
            className="absolute bottom-2 left-0 right-0 flex justify-between items-center px-2 md:px-8"
          >
            {previousProject ? (
              <Link
                href={`/projects/${previousProject.slug}`}
                className="nav-btn text-xs md:text-sm tracking-[0.25em] uppercase text-white font-bold mix-blend-difference"
              >
                <span>Back</span>
              </Link>
            ) : (
              <span className="text-xs md:text-sm tracking-[0.25em] uppercase text-white/40 font-bold mix-blend-difference">
                Back
              </span>
            )}
            <Link
              href="/"
              className="nav-btn text-xs md:text-sm tracking-[0.25em] uppercase text-white font-bold mix-blend-difference"
            >
              <span>Home</span>
            </Link>
            {nextProject ? (
              <Link
                href={`/projects/${nextProject.slug}`}
                className="nav-btn text-xs md:text-sm tracking-[0.25em] uppercase text-white font-bold mix-blend-difference"
              >
                <span>Next</span>
              </Link>
            ) : (
              <span className="text-xs md:text-sm tracking-[0.25em] uppercase text-white/40 font-bold mix-blend-difference">
                Next
              </span>
            )}
          </nav>
        </div>
      </section>

      {/* Titre avec étoiles */}
      <section className="bg-[#f4f5f0] px-4 mt-5 md:mt-20">
        <div className="flex items-center justify-center gap-4">
          <Asterisk
            ref={starLeftRef}
            strokeWidth={1}
            className="h-10 w-10 md:h-28 md:w-28 text-[#1e1f1f] md:ml-5"
            style={{ rotate: "45deg" }}
          />
          <h1
            ref={titleRef}
            className="font-script text-4xl md:text-[10rem] text-gray-900 whitespace-nowrap"
          >
            {project.title}
          </h1>
          <Asterisk
            ref={starRightRef}
            strokeWidth={1}
            className="h-10 w-10 md:h-28 md:w-28 text-[#1e1f1f] md:ml-5"
            style={{ rotate: "45deg" }}
          />
        </div>
      </section>

      <style jsx global>{`
        .nav-btn {
          transition: all 0.3s ease;
          display: inline-block;
        }
        .nav-btn:hover {
          transform: scale(1.1);
        }
        .nav-btn:hover span {
          display: inline-block;
          animation: textBounce 0.3s ease;
        }
        @keyframes textBounce {
          0% { transform: translateY(0); }
          50% { transform: translateY(-3px); }
          100% { transform: translateY(0); }
        }
      `}</style>
    </div>
  );
}